text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 전제로 금요일 15:00 KST를 공개 릴리스 목표 시점으로 둔다."
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토로 넘어간다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경하자",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스",
        "note": "확정 일정이 아니라 내부 스트레치 목표로만 남겼다."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었지만 소유자는 지정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "명시적 확인"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "명시적 확인"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "Minjun의 스모크 결과 공유 후",
      "status": "대기",
      "source_certainty": "명시적 확인, 정확한 시한 미지정"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "미배정",
      "source_certainty": "제안 수준, 소유자 미확정"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00 KST까지 스모크 테스트 결과가 실제로 공유되었는지 확인한다.",
      "스모크 결과 공유 뒤 tarball 경로 확인 결과를 점검한다.",
      "금요일 12:00 KST까지 failure triage note가 action_items.md에 반영되었는지 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 후속 확인한다."
    ],
    "do_not_invent": [
      "고객명이나 외부 파트너를 추가하지 않는다.",
      "예산 정보를 추가하지 않는다.",
      "보안 사고, 운영 장애, 법무 승인 요구를 추가하지 않는다.",
      "명시되지 않은 소유자, 승인자, 마감 시각을 단정하지 않는다."
    ]
  },
  "non_invention_rules": [
    "인라인 공개용 합성 픽스처에 없는 사실은 추가하지 않는다.",
    "확정된 결정과 반려된 제안, 내부 스트레치 목표, 위험, 미해결 질문을 서로 섞어 쓰지 않는다.",
    "고객, 예산, 보안, 장애, 법무 관련 사실은 명시된 비사실 범위를 유지한다.",
    "소유자나 마감이 명시되지 않은 항목은 null 또는 미지정으로 두고 추정으로 보완하지 않는다."
  ]
}
